import { Link } from 'react-router-dom';

const ServiceCard = ({ icon: Icon, price, priceLabel, title, description }) => {
  return (
    <div className="service-card">
      <div className="card-header">
        <div className="card-icon-wrapper">
          <Icon className="card-icon" />
        </div>

        <div className="card-price-info">
          <span className="card-price-label">A partir de</span>
          <span className="card-price">R$ {price}</span>
        </div>
      </div>
      
      <h3 className="card-title">{title}</h3>
      <p className="card-description">{description}</p>
      <div className="card-footer">
        <Link to="#" className="btn btn-secondary">Saiba Mais</Link>
        <Link to="#" className="btn btn-primary">Agendar</Link>
      </div>
    </div>
  );
};

export default ServiceCard;
